<?php require dirname(__DIR__).'/includes/pawn_bootstrap.php';pawn_require_csrf();$id=(int)($_POST['pawn_entry_id']??0);$collection=(string)($_POST['collection_date']??'');$from=(string)($_POST['from_date']??'');$to=(string)($_POST['to_date']??'');$interest=(float)($_POST['interest_amount']??0);$penalty=(float)($_POST['penalty_amount']??0);$total=$interest+$penalty;$method=(int)($_POST['payment_method_id']??0);if($id<=0||$interest<=0||$total<=0)pawn_json(false,'Invalid interest details.');$receipt=pawn_next_no($conn,$businessId,$branchId,'PawnInterest','INT');$conn->begin_transaction();try{$st=$conn->prepare("SELECT id FROM pawn_entries WHERE id=? AND business_id=? AND branch_id=? AND status IN ('Active','Partially Paid') FOR UPDATE");$st->bind_param('iii',$id,$businessId,$branchId);$st->execute();if(!$st->get_result()->fetch_assoc())throw new Exception('Pawn is not active.');$st->close();$methodVal=$method?:null;$st=$conn->prepare('INSERT INTO pawn_interest_collections(business_id,branch_id,pawn_entry_id,receipt_no,collection_date,from_date,to_date,interest_amount,penalty_amount,total_amount,payment_method_id,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)');$st->bind_param('iiissssdddii',$businessId,$branchId,$id,$receipt,$collection,$from,$to,$interest,$penalty,$total,$methodVal,$userId);$st->execute();$st->close();$st=$conn->prepare('UPDATE pawn_entries SET total_interest_collected=total_interest_collected+? WHERE id=? AND business_id=?');$st->bind_param('dii',$interest,$id,$businessId);$st->execute();$st->close();$conn->commit();pawn_json(true,'Interest collected successfully.');}catch(Throwable $e){$conn->rollback();pawn_json(false,$e->getMessage());}
